	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/closures", wrapper.GetClosures)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/closures", wrapper.AddClosure)
	m.HandleFunc(http.MethodDelete+" "+options.BaseURL+"/closures/{id}", wrapper.DeleteClosure)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/closures/{id}", wrapper.GetClosure)
	m.HandleFunc(http.MethodPatch+" "+options.BaseURL+"/closures/{id}", wrapper.UpdateClosure)
