	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/entries/{key}/{value}", wrapper.GetEntry)
	m.HandleFunc(http.MethodPatch+" "+options.BaseURL+"/entries/{key}/{value}", wrapper.UpdateEntry)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/entries/{key}/{value}/networks", wrapper.GetNetworksForEntry)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/entries/{key}/{value}/networks", wrapper.AddNetworkForEntry)
	m.HandleFunc(http.MethodDelete+" "+options.BaseURL+"/entries/{key}/{value}/networks/{id}", wrapper.DeleteNetworkForEntry)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/entries/{key}/{value}/tiers", wrapper.GetTiersForEntry)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/entries/{key}/{value}/tiers", wrapper.AddTierForEntry)
	m.HandleFunc(http.MethodDelete+" "+options.BaseURL+"/entries/{key}/{value}/tiers/{id}", wrapper.DeleteTierForEntry)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/entry-networks", wrapper.GetEntryNetworks)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/entry-networks", wrapper.AddEntryNetwork)
	m.HandleFunc(http.MethodDelete+" "+options.BaseURL+"/entry-networks/{id}", wrapper.DeleteEntryNetwork)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/entry-networks/{id}", wrapper.GetEntryNetworkByID)
